fn update_events_borders<C: Callbacks>(events: &[InputEvent], state: &mut C) {
    for ev in events {
        if let InputEvent::Press { x, y } = ev {
            let new_focus =
                if *x < 400 && *y < 96 { Some(0) }
                else if *x >= 400 && *x < 800 && *y < 96 { Some(1) }
                else { None };
            *FOCUSED.lock().unwrap() = new_focus;
            if *x < 400 && *y < 96 {
                state.nav(&["Widget"]);
            }
            if *x >= 400 && *x < 800 && *y < 96 {
                state.nav(&["Clickable"]);
            }
        }
    }
}

fn update_events_clickable<C: Callbacks>(events: &[InputEvent], state: &mut C) {
    for ev in events {
        if let InputEvent::Press { x, y } = ev {
            let new_focus =
                if *x < 400 && *y < 96 { Some(0) }
                else if *x >= 400 && *x < 800 && *y < 96 { Some(1) }
                else if *x < 800 && *y >= 96 && *y < 192 { Some(2) }
                else if *x < 800 && *y >= 192 && *y < 288 { Some(3) }
                else if *x < 800 && *y >= 288 && *y < 384 { Some(4) }
                else if *x < 800 && *y >= 384 && *y < 480 { Some(5) }
                else { None };
            *FOCUSED.lock().unwrap() = new_focus;
            if *x < 400 && *y < 96 {
                state.nav(&["Borders"]);
            }
            if *x >= 400 && *x < 800 && *y < 96 {
                state.nav(&["Complex"]);
            }
            if *x < 800 && *y >= 96 && *y < 192 {
                state.function_cl();
            }
            if *x < 800 && *y >= 192 && *y < 288 {
                state.function_pr(&["hello"]);
            }
            if *x < 800 && *y >= 288 && *y < 384 {
                state.fn_multi(&["a", "b"]);
            }
            if *x < 800 && *y >= 384 && *y < 480 {
                state.fn3();
            }
        }
    }
}

fn update_events_complex<C: Callbacks>(events: &[InputEvent], state: &mut C) {
    for ev in events {
        if let InputEvent::Press { x, y } = ev {
            let new_focus =
                if *x < 400 && *y < 240 { Some(0) }
                else if *x >= 400 && *x < 800 && *y < 240 { Some(1) }
                else { None };
            *FOCUSED.lock().unwrap() = new_focus;
            if *x < 400 && *y < 240 {
                state.nav(&["Clickable"]);
            }
            if *x >= 400 && *x < 800 && *y < 240 {
                state.nav(&["DynStat"]);
            }
            if *x >= 400 && *x < 800 && *y >= 400 && *y < 480 {
                state.click();
            }
        }
    }
}

